{
  "command": "duckdb '/workspace/DataAgentBench/query_crmarenapro/query_dataset/sales_pipeline.duckdb' \"DESCRIBE Contract; DESCRIBE Opportunity;\"",
  "description": "Check Contract and Opportunity"
}

{
  "command": "duckdb '/workspace/DataAgentBench/query_crmarenapro/query_dataset/sales_pipeline.duckdb' \"SELECT MIN(CompanySignedDate), MAX(CompanySignedDate), COUNT(*) FROM Contract WHERE CompanySignedDate IS NOT NULL;\"",
  "description": "Check Contract dates"
}

{
  "command": "sqlite3 '/workspace/DataAgentBench/query_crmarenapro/query_dataset/products_orders.db' \"SELECT MIN(EffectiveDate), MAX(EffectiveDate), COUNT(*) FROM 'Order';\"",
  "description": "Check Order dates"
}

{
  "command": "sqlite3 '/workspace/DataAgentBench/query_crmarenapro/query_dataset/products_orders.db' \"SELECT o.OwnerId, SUM(CAST(REPLACE(oi.Quantity,'#','') AS REAL) * CAST(REPLACE(oi.UnitPrice,'#','') AS REAL)) AS sales FROM 'Order' o JOIN OrderItem oi ON REPLACE(oi.OrderId,'#','') = REPLACE(o.Id,'#','') WHERE REPLACE(o.EffectiveDate,'#','') >= '2022-06-25' AND REPLACE(o.EffectiveDate,'#','') <= '2022-11-25' GROUP BY o.OwnerId ORDER BY sales DESC LIMIT 10;\"",
  "description": "Sales by owner in past 5 months"
}

{
  "command": "sqlite3 '/workspace/DataAgentBench/query_crmarenapro/query_dataset/products_orders.db' \"SELECT REPLACE(o.OwnerId,'#','') AS owner, SUM(CAST(REPLACE(oi.Quantity,'#','') AS REAL) * CAST(REPLACE(oi.UnitPrice,'#','') AS REAL)) AS sales FROM 'Order' o JOIN OrderItem oi ON REPLACE(oi.OrderId,'#','') = REPLACE(o.Id,'#','') WHERE REPLACE(o.EffectiveDate,'#','') >= '2022-06-25' AND REPLACE(o.EffectiveDate,'#','') <= '2022-11-25' GROUP BY owner ORDER BY sales DESC LIMIT 10;\"",
  "description": "Sales by owner normalized"
}

{
  "command": "duckdb '/workspace/DataAgentBench/query_crmarenapro/query_dataset/sales_pipeline.duckdb' \"SELECT COUNT(*) FROM Contract WHERE REPLACE(CompanySignedDate,'#','') >= '2022-06-25' AND REPLACE(CompanySignedDate,'#','') <= '2022-11-25';\"",
  "description": "Count contracts in window"
}

{
  "command": "duckdb '/workspace/DataAgentBench/query_crmarenapro/query_dataset/sales_pipeline.duckdb' \"COPY (SELECT REPLACE(AccountId,'#','') as acct, REPLACE(CompanySignedDate,'#','') as csd FROM Contract WHERE REPLACE(CompanySignedDate,'#','') >= '2022-06-25' AND REPLACE(CompanySignedDate,'#','') <= '2022-11-25') TO '/tmp/eligible_contracts.csv' (HEADER, DELIMITER ',');\" && wc -l /tmp/eligible_contracts.csv",
  "description": "Dump eligible contracts"
}

{
  "command": "duckdb '/workspace/DataAgentBench/query_crmarenapro/query_dataset/sales_pipeline.duckdb' "ATTACH '/workspace/DataAgentBench/query_crmarenapro/query_dataset/products_orders.db' AS po (TYPE SQLITE, READ_ONLY); 
SELECT REPLACE(o.OwnerId,'#','') AS owner, SUM(CAST(REPLACE(oi.Quantity,'#','') AS DOUBLE) * CAST(REPLACE(oi.UnitPrice,'#','') AS DOUBLE)) AS sales 
FROM po.\"Order\" o 
JOIN po.OrderItem oi ON REPLACE(oi.OrderId,'#','') = REPLACE(o.Id,'#','') 
WHERE REPLACE(o.AccountId,'#','') IN (
  SELECT REPLACE(AccountId,'#','') FROM Contract 
  WHERE REPLACE(CompanySignedDate,'#','') >= '2022-06-25' 
    AND REPLACE(CompanySignedDate,'#','') <= '2022-11-25'
)
GROUP BY owner ORDER BY sales DESC LIMIT 10;"",
  "description": "Sales by owner via eligible contracts"
}
